const priority = {
  low: 1,
  medium: 2,
  high: 3,
  critical: 4
};

const anomalies = $json.anomalies ?? [];

let highest = "low";

for (const anomaly of anomalies) {
  if (priority[anomaly.severity] > priority[highest]) {
    highest = anomaly.severity;
  }
}

return [
  {
    json: {
      ...$json,
      highestSeverity: highest
    }
  }
];
